#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, X, D;
        scanf("%lld %lld %lld", &N, &X, &D);
        long long daily = 5LL * X;
        long long days_with_food = (daily == 0) ? 0 : N / daily;
        long long total = days_with_food + D;
        printf("%lld\n", total);
    }
    return 0;
}

